# Shape hierarchy module - demonstrates cross-module inheritance
@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float:
        ...

    @virtual
    def describe(self) -> str:
        return "Shape: " + self.name

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__("Rectangle")
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return "Rectangle(" + str(self.width) + "x" + str(self.height) + ")"

class Circle(Shape):
    radius: float

    def __init__(self, radius: float):
        super().__init__("Circle")
        self.radius = radius

    @override
    def area(self) -> float:
        # pi * r^2
        return 3.14159 * self.radius * self.radius

def create_default_rectangle() -> Rectangle:
    return Rectangle(10.0, 5.0)

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total = total + shape.area()
    return total

