# Utility module with interfaces and services

interface ILogger:
    def log(self, message: str) -> None

class ConsoleLogger:
    prefix: str

    def __init__(self, prefix: str):
        self.prefix = prefix

    def log(self, message: str) -> None:
        print("[" + self.prefix + "] " + message)

class ShapeAnalyzer:
    logger: ILogger

    def __init__(self, logger: ILogger):
        self.logger = logger

    def analyze(self, shape: object) -> None:
        from shapes import Shape, Rectangle, Circle

        if isinstance(shape, Circle):
            c: Circle = shape
            self.logger.log("Circle with radius " + str(c.radius))
        elif isinstance(shape, Rectangle):
            r: Rectangle = shape
            self.logger.log("Rectangle " + str(r.width) + "x" + str(r.height))
        elif isinstance(shape, Shape):
            s: Shape = shape
            self.logger.log("Generic shape: " + s.name)

def get_pi_approximation() -> float:
    return 3.14159
